import React, { useState } from "react";
import {Link,Routes, Route, Navigate, BrowserRouter} from 'react-router-dom';
import Login from "./Login";
import './Design.css';
document.body.style.overflow = "hidden"

function Signup(){
const[email,setEmail]=useState('');
const[usertype,setUserType]=useState('');
const[username,setUsername]=useState('');
const[mobileNumber,setMobileNumber]=useState('');
const[password,setPassword]=useState('');
const[confirmpassword,setConfirmPassword]=useState('');

const handleClick=(e)=>{
e.preventDefault()
const user=[usertype,email,username,mobileNumber,password,confirmpassword]
fetch("http://localhost:8080/user/login",
{
method:"POST",
headers:{"Content-Type":"application/json"},
body:JSON.stringify(user)
}).then(()=>{alert("Registration Completed")})

}
    return (
    <>  
<div className="bg1">
<br></br>
<br></br>
<div className="titlebar">
        Register
    </div>

    <div className="form">
        <form >
        <br></br>
            <select id="usertype" value={usertype} onChange={(e)=>setUserType(e.target.value)}>
                <option id = "admin" value = "admin" >Admin</option>
                <option id = "user" value = "user">User</option>
            </select>
            <br></br>
            <input placeholder = "Email" type = "email" id = "email" name='email' value={email} onChange={(e)=>setEmail(e.target.value)}></input>
            <br></br>
            <input placeholder = "Username" type = "text" id =  "username" name = "username" value={username} onChange={(e)=>setUsername(e.target.value)}></input>
            <br></br>
            <input placeholder = "Mobile Number" type = "text" id =  "mobileNumber" name = "mobileNumber" value={mobileNumber} onChange={(e)=>setMobileNumber(e.target.value)}></input>
            <br></br>
            <input placeholder = "Password" type = "text" id =  "password" name = "password" value={password} onChange={(e)=>setPassword(e.target.value)}></input>
            <br></br>
            <input placeholder = "Confirm Password" type = "text" id =  "confirmpassword" name = "confirmpassowrd" value={confirmpassword} onChange={(e)=>setConfirmPassword(e.target.value)}></input>
        </form>
        <div className="center">
        <button id = "submitButton" type='submit' value="Submit" onClick={handleClick}> Submit </button>
        </div>
        <br></br>
    </div>
    <p >Already a Member?  < Link to = "/Login" className="link"> Login</Link> </p>
    <br></br>
</div>
    </>)
}



export default Signup;
